      woo_link_status='Enlazado', woo_link_notes='Enlace creado por Lote D final.',
      woo_synced_at=now(), hub_item_code=r.hub_item_code,
      item_record_type=case when r.is_pack then 'woo_pack' else 'woo_item' end,
      source_row=jsonb_build_object('source','woo_cierre_lote_D','woo_status',r.woo_status,'permalink',r.permalink,'original_sku',r.woo_sku),
      updated_at=now()
    where i.woo_id=r.woo_id or i.hub_item_code=r.hub_item_code;

    if not found then
      insert into public.inventory_items(
        item_id,name,family,subgroup,size,materials,commercial_status,is_pack,source,notes,
        woo_item_kind,woo_id,woo_parent_id,woo_sku,woo_name,woo_type,woo_price,woo_categories,
        woo_link_status,woo_link_notes,woo_synced_at,hub_item_code,item_record_type,base_item_code,source_row,updated_at)
      values(
        r.item_id,r.name,r.family,nullif(r.subgroup,''),nullif(r.size,''),nullif(r.materials,''),
        r.commercial_status,r.is_pack,'WooCommerce cierre final Lote D',
        'Item Woo independiente creado para cerrar enlace operativo.',r.woo_item_kind,r.woo_id,r.woo_parent_id,
        nullif(r.woo_sku,''),r.woo_name,r.woo_type,nullif(r.woo_price,''),r.woo_categories,
        'Enlazado','Enlace creado por Lote D final.',now(),r.hub_item_code,
        case when r.is_pack then 'woo_pack' else 'woo_item' end,null,
        jsonb_build_object('source','woo_cierre_lote_D','woo_status',r.woo_status,'permalink',r.permalink,'original_sku',r.woo_sku),now())
      on conflict(item_id) do update set
        name=excluded.name,family=excluded.family,subgroup=excluded.subgroup,size=excluded.size,
        materials=excluded.materials,commercial_status=excluded.commercial_status,is_pack=excluded.is_pack,
        woo_item_kind=excluded.woo_item_kind,woo_id=excluded.woo_id,woo_parent_id=excluded.woo_parent_id,
        woo_sku=excluded.woo_sku,woo_name=excluded.woo_name,woo_type=excluded.woo_type,
        woo_price=excluded.woo_price,woo_categories=excluded.woo_categories,
        woo_link_status=excluded.woo_link_status,woo_link_notes=excluded.woo_link_notes,
        hub_item_code=excluded.hub_item_code,item_record_type=excluded.item_record_type,
        source_row=excluded.source_row,updated_at=now();
    end if;
  end loop;
end
$futonhub$;

select count(*) as items_lote_d,
       count(*) filter(where woo_link_status='Enlazado') as enlazados
from public.inventory_items
where source='WooCommerce cierre final Lote D';

select item_id,hub_item_code,woo_id,woo_parent_id,woo_sku,item_record_type,woo_link_status,name
from public.inventory_items
where source='WooCommerce cierre final Lote D'
order by woo_id;
